const body = $input.first().json.body;

if (!body || !body.entry || body.entry.length === 0) {
  return [{ json: { skip: true } }];
}

const entry = body.entry[0];
const changes = entry.changes?.[0];
const value = changes?.value;

if (!value || !value.messages || value.messages.length === 0) {
  return [{ json: { skip: true } }];
}

const message = value.messages[0];
const contact = value.contacts?.[0];

const senderNumber = message.from;
const senderName = contact?.profile?.name || 'User';
const messageType = message.type;
let messageText = '';

if (messageType === 'text') {
  messageText = message.text?.body || '';
} else if (messageType === 'interactive') {
  const interactive = message.interactive;
  if (interactive.type === 'button_reply') {
    messageText = interactive.button_reply?.id || '';
  } else if (interactive.type === 'list_reply') {
    messageText = interactive.list_reply?.id || '';
  }
}

const phoneNumberId = value.metadata?.phone_number_id;

return [{
  json: {
    skip: false,
    senderNumber,
    senderName,
    messageText: messageText.toLowerCase().trim(),
    messageTextOriginal: messageText,
    messageType,
    phoneNumberId,
    timestamp: message.timestamp
  }
}];

const msg = $json.messageText;
const senderNumber = $json.senderNumber;
const senderName = $json.senderName;

// Keywords categorization
const greetings = ['hi', 'hello', 'hey', 'salam', 'assalam', 'assalamualaikum', 'helo', 'start', 'menu'];
const priceKeywords = ['price', 'rate', 'cost', 'qeemat', 'amount', 'how much', 'kitna'];
const orderKeywords = ['order', 'buy', 'purchase', 'book', 'khareed', 'chahiye', 'want'];
const trackKeywords = ['track', 'status', 'where', 'kahan', 'parcel', 'delivery', 'kab'];
const supportKeywords = ['help', 'support', 'problem', 'issue', 'complaint', 'masla', 'madad'];
const humanKeywords = ['agent', 'human', 'representative', 'banda', 'insaan', 'talk to'];

let intent = 'unknown';

if (greetings.some(g => msg.includes(g))) {
  intent = 'greeting';
} else if (priceKeywords.some(k => msg.includes(k))) {
  intent = 'pricing';
} else if (orderKeywords.some(k => msg.includes(k))) {
  intent = 'order';
} else if (trackKeywords.some(k => msg.includes(k))) {
  intent = 'tracking';
} else if (humanKeywords.some(k => msg.includes(k))) {
  intent = 'human_agent';
} else if (supportKeywords.some(k => msg.includes(k))) {
  intent = 'support';
} else if (msg === '1') {
  intent = 'pricing';
} else if (msg === '2') {
  intent = 'order';
} else if (msg === '3') {
  intent = 'tracking';
} else if (msg === '4') {
  intent = 'support';
} else if (msg === '5') {
  intent = 'human_agent';
}

return [{ json: { ...$json, intent } }];

